                | SyntaxKind::Integer
                | SyntaxKind::IntegerNegative
                | SyntaxKind::IntegerPositive
                | SyntaxKind::IriLit
                | SyntaxKind::Iriref
                | SyntaxKind::IsBlankLit
                | SyntaxKind::IsIriLit
                | SyntaxKind::IsLiteralLit
                | SyntaxKind::IsNumericLit
                | SyntaxKind::IsUriLit
